import React, { useEffect, useState } from 'react';

export default function ExpenseForm({ initial = null, onSubmit, onCancel, submitting = false }) {
  const [title, setTitle] = useState('');
  const [amount, setAmount] = useState('');
  const [date, setDate] = useState('');
  const [errors, setErrors] = useState({});

  useEffect(() => {
    if (initial) {
      setTitle(initial.category || '');
      setAmount(initial.amount != null ? String(initial.amount) : '');
      setDate(initial.date ? new Date(initial.date).toISOString().split('T')[0] : '');
    } else {
      setTitle('');
      setAmount('');
      setDate('');
    }
    setErrors({});
  }, [initial]);

  const validate = () => {
    const e = {};
    if (!title || title.trim().length === 0) e.title = 'Title is required';
    if (!amount || Number.isNaN(Number(amount)) || Number(amount) <= 0)
      e.amount = 'Enter a valid amount';
    return e;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const eErr = validate();
    setErrors(eErr);
    if (Object.keys(eErr).length > 0) return;

    onSubmit({
      title: title.trim(),
      amount: Number(amount),
      date,
    });
  };

  return (
    <div className="bg-gradient-to-br from-slate-800/80 to-slate-900 border border-white/10 rounded-2xl p-6 mb-6 shadow-xl shadow-black/30">

      <h2 className="text-xl font-semibold mb-5 text-white tracking-wide">
        {initial ? 'Edit Expense' : 'Add Expense'}
      </h2>

      <form onSubmit={handleSubmit} className="grid md:grid-cols-4 gap-5 items-end">

        {/* Title */}
        <div className="flex flex-col">
          <label className="text-xs text-gray-400 mb-1">Title</label>

          <div className="relative">
            <span className="absolute left-3 top-2.5 text-gray-400">📝</span>
            <input
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="Groceries"
              className="w-full bg-white/5 border border-white/10 rounded-xl pl-9 pr-3 py-2 text-white outline-none focus:ring-2 focus:ring-blue-500 transition"
            />
          </div>

          {errors.title && <span className="text-xs text-red-400 mt-1">{errors.title}</span>}
        </div>

        {/* Amount */}
        <div className="flex flex-col">
          <label className="text-xs text-gray-400 mb-1">Amount</label>

          <div className="relative">
            <span className="absolute left-3 top-2.5 text-gray-400">₹</span>
            <input
              type="number"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              placeholder="0.00"
              className="w-full bg-white/5 border border-white/10 rounded-xl pl-9 pr-3 py-2 text-white outline-none focus:ring-2 focus:ring-green-500 transition"
            />
          </div>

          {errors.amount && <span className="text-xs text-red-400 mt-1">{errors.amount}</span>}
        </div>

        {/* Date */}
        <div className="flex flex-col">
          <label className="text-xs text-gray-400 mb-1">Date</label>

          <div className="relative">
            <span className="absolute left-3 top-2.5 text-gray-400">📅</span>
            <input
              type="date"
              value={date}
              onChange={(e) => setDate(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-xl pl-9 pr-3 py-2 text-white outline-none focus:ring-2 focus:ring-purple-500 transition"
            />
          </div>
        </div>

        {/* Buttons */}
        <div className="flex gap-2">

          {initial && (
            <button
              type="button"
              onClick={onCancel}
              className="w-full bg-white/10 text-white py-2 rounded-xl hover:bg-white/20 transition"
            >
              Cancel
            </button>
          )}

          <button
            type="submit"
            disabled={submitting}
            className="w-full bg-gradient-to-r from-green-500 to-emerald-400 text-black font-semibold py-2 rounded-xl hover:scale-105 hover:shadow-lg hover:shadow-green-500/20 transition disabled:opacity-50"
          >
            {submitting
              ? initial
                ? 'Updating...'
                : 'Adding...'
              : initial
              ? 'Update'
              : 'Add'}
          </button>

        </div>

      </form>
    </div>
  );
}